/**
 * Test script: verifies that each validation check in the deployed
 * clearance contract actually rejects bad proofs.
 *
 * Usage:
 *   npx tsx scripts/test-contract-checks.ts                    # query tests only
 *   XION_MNEMONIC="..." npx tsx scripts/test-contract-checks.ts  # full test suite
 */

import { CosmWasmClient, SigningCosmWasmClient } from "@cosmjs/cosmwasm-stargate";
import { DirectSecp256k1HdWallet } from "@cosmjs/proto-signing";
import { GasPrice } from "@cosmjs/stargate";
import { createHash } from "crypto";

const RPC = "https://rpc.xion-testnet-2.burnt.com:443";
const REST = "https://api.xion-testnet-2.burnt.com";
const CLEARANCE =
  "xion1kk0scnwmjnt74gqcsk7dqpq0qwg2qvzdtagtylfg6grz0zyaz2wqzrsvvp";
const NFT_CONTRACT =
  "xion1qfxvqh8r397ga3qsjcywfkc2dlqyxw6h85wnttdwwud8z43ew3jqm6ard2";

const TEE_PUBKEY_HEX =
  "d4aea0ab2a5cfdc479e2b02599d8e30d7dcbcc11bc550681a15d0777d298867465adda0877a31bf4a80dd227d0b1c53f263afe5136081698ff89101622c5616f";

// Real TDX attestation quote from a production CVM run (hex → base64).
// This quote has a valid ECDSA-P256 signature over the header+body,
// signed by the attestation key above. Used to test check 5 (REPORTDATA
// binding) — proves the crypto pipeline actually works end-to-end.
// REPORTDATA first 32 bytes = SHA-256 of the original result JSON.
const REAL_QUOTE_HEX =
  "";

function hexToBase64(hex: string): string {
  const bytes = Buffer.from(hex, "hex");
  return bytes.toString("base64");
}

// ── Helpers ──

function buildQuote(opts: {
  version?: number;
  teeType?: number;
  attKey?: Buffer;
  reportData?: Buffer;
  signature?: Buffer;
  size?: number;
}): Buffer {
  const size = opts.size ?? 800;
  const buf = Buffer.alloc(size, 0);
  buf.writeUInt16LE(opts.version ?? 4, 0);
  buf.writeUInt32LE(opts.teeType ?? 0x81, 4);
  if (opts.attKey) opts.attKey.copy(buf, 0x2bc, 0, 64);
  if (opts.reportData) opts.reportData.copy(buf, 0x238, 0, Math.min(opts.reportData.length, 64));
  if (opts.signature) opts.signature.copy(buf, 0x27c, 0, 64);
  return buf;
}

function sha256(data: string): Buffer {
  return createHash("sha256").update(data).digest();
}

let passCount = 0;
let failCount = 0;

function pass(label: string, detail: string) {
  console.log(`  PASS  ${label} — ${detail}`);
  passCount++;
}

function fail(label: string, detail: string) {
  console.log(`  FAIL  ${label} — ${detail}`);
  failCount++;
}

// ── Part 1: Query tests (no wallet needed) ──

async function runQueryTests() {
  console.log("── Query endpoint tests ──\n");
  const client = await CosmWasmClient.connect(RPC);

  // get_config
  const config = await client.queryContractSmart(CLEARANCE, { get_config: {} });
  if (config.admin && config.nft_contract) {
    pass("get_config", `admin=${config.admin.slice(0, 15)}... nft=${config.nft_contract.slice(0, 15)}...`);
  } else {
    fail("get_config", `unexpected response: ${JSON.stringify(config)}`);
  }

  // Verify NFT contract matches what we expect
  if (config.nft_contract === NFT_CONTRACT) {
    pass("nft_contract match", "on-chain config matches app env var");
  } else {
    fail("nft_contract match", `expected ${NFT_CONTRACT}, got ${config.nft_contract}`);
  }

  // get_badge_count
  const badges = await client.queryContractSmart(CLEARANCE, { get_badge_count: {} });
  if (typeof badges.count === "number") {
    pass("get_badge_count", `${badges.count} badges minted`);
  } else {
    fail("get_badge_count", `unexpected: ${JSON.stringify(badges)}`);
  }

  // get_tee_pubkey
  const tee = await client.queryContractSmart(CLEARANCE, { get_tee_pubkey: {} });
  if (tee.pubkey === TEE_PUBKEY_HEX) {
    pass("get_tee_pubkey", "matches expected CVM attestation key");
  } else {
    fail("get_tee_pubkey", `mismatch: got ${tee.pubkey?.slice(0, 30)}...`);
  }

  // Verify pubkey length (64 bytes = 128 hex chars)
  if (tee.pubkey.length === 128) {
    pass("tee_pubkey length", "64 bytes (valid P-256 x||y)");
  } else {
    fail("tee_pubkey length", `expected 128 hex chars, got ${tee.pubkey.length}`);
  }

  // Cross-check: query NFT contract for num_tokens
  const nftCount = await client.queryContractSmart(NFT_CONTRACT, { num_tokens: {} });
  if (nftCount.count === badges.count) {
    pass("badge count cross-check", `clearance counter (${badges.count}) == NFT num_tokens (${nftCount.count})`);
  } else {
    fail("badge count cross-check", `clearance=${badges.count} vs NFT=${nftCount.count}`);
  }

  client.disconnect();
}

// ── Part 2: Execute tests (wallet required) ──

type TestCase = {
  name: string;
  result: string;
  quote: string;
  expectedError: string;
};

function buildExecuteTests(sender: string): TestCase[] {
  const realAttKey = Buffer.from(TEE_PUBKEY_HEX, "hex");
  const wrongAttKey = Buffer.alloc(64, 0xff);

  // For check 8 test: build a quote that passes 1-3 but has wrong REPORTDATA
  // (won't pass sig check in practice, but documents what we'd test)
  const resultJson = JSON.stringify({
    address: sender,
    clean: true,
    message_count: 0,
    suspect: "jeevacation@gmail.com",
    timestamp: Math.floor(Date.now() / 1000),
  });

  return [
    {
      name: "Check 1: quote too short (<764 bytes)",
      result: "{}",
      quote: Buffer.alloc(100, 0).toString("base64"),
      expectedError: "too short",
    },
    {
      name: "Check 2a: wrong version (v3)",
      result: "{}",
      quote: buildQuote({ version: 3, teeType: 0x81 }).toString("base64"),
      expectedError: "not TDX v4",
    },
    {
      name: "Check 2b: wrong TEE type (SGX)",
      result: "{}",
      quote: buildQuote({ version: 4, teeType: 0x00 }).toString("base64"),
      expectedError: "not TDX v4",
    },
    {
      name: "Check 3: attestation key mismatch",
      result: "{}",
      quote: buildQuote({ attKey: wrongAttKey }).toString("base64"),
      expectedError: "attestation key mismatch",
    },
    {
      name: "Check 4: invalid ECDSA signature",
      result: "{}",
      quote: buildQuote({ attKey: realAttKey }).toString("base64"),
      expectedError: "invalid signature",
    },
    // ── Check 5: real TDX quote + tampered result ──
    // This is the most important test. The real quote has a valid ECDSA
    // signature from the CVM's attestation key, so checks 1-4 pass.
    // But the result string doesn't match the SHA-256 in REPORTDATA,
    // proving the contract catches any post-hoc tampering.
    {
      name: "Check 5: REPORTDATA mismatch (real TDX quote, tampered result)",
      result: '{"address":"xion1fake","clean":true,"message_count":0,"suspect":"x","timestamp":0}',
      quote: hexToBase64(REAL_QUOTE_HEX),
      expectedError: "report_data mismatch",
    },
  ];
}

async function runExecuteTests() {
  const mnemonic = process.env.XION_MNEMONIC;
  if (!mnemonic) {
    console.log("── Execute tests (skipped — no XION_MNEMONIC) ──\n");
    console.log("  To run: XION_MNEMONIC=\"your mnemonic\" npx tsx scripts/test-contract-checks.ts\n");
    console.log("  These tests send crafted bad proofs to the contract and verify");
    console.log("  each validation check rejects with the correct error.\n");
    console.log("  Checks 1-5 are tested (check 5 uses a real TDX quote).");
    console.log("  Checks 6-9 require a matching result+quote pair → test via the real flow.\n");
    return;
  }

  console.log("── Execute tests (on-chain rejection) ──\n");

  const wallet = await DirectSecp256k1HdWallet.fromMnemonic(mnemonic, {
    prefix: "xion",
  });
  const [account] = await wallet.getAccounts();
  const client = await SigningCosmWasmClient.connectWithSigner(RPC, wallet, {
    gasPrice: GasPrice.fromString("0.025uxion"),
  });
  const sender = account.address;
  console.log(`  Sender: ${sender}\n`);

  const tests = buildExecuteTests(sender);

  for (const test of tests) {
    try {
      await client.execute(
        sender,
        CLEARANCE,
        { submit_proof: { result: test.result, quote: test.quote } },
        "auto"
      );
      fail(test.name, "tx succeeded (should have been rejected)");
    } catch (err: any) {
      const msg = err.message || String(err);
      if (msg.toLowerCase().includes(test.expectedError.toLowerCase())) {
        pass(test.name, `rejected: "${test.expectedError}"`);
      } else {
        fail(test.name, `wrong error — expected "${test.expectedError}", got: "${msg.slice(0, 150)}"`);
      }
    }
  }

  client.disconnect();
}

// ── Main ──

async function main() {
  console.log("Clearance Contract Validation Test Suite\n");
  console.log(`Contract: ${CLEARANCE}`);
  console.log(`NFT:      ${NFT_CONTRACT}`);
  console.log(`RPC:      ${RPC}\n`);

  await runQueryTests();
  console.log();
  await runExecuteTests();

  console.log(`\n── Results: ${passCount} passed, ${failCount} failed ──\n`);
  process.exit(failCount > 0 ? 1 : 0);
}

main().catch(console.error);
